mapper.select:
SELECT COUNT(1)
FROM topics
WHERE name = #{topicName}

mapper.update:
UPDATE post_interactions
SET liked = #{liked},
    saved = #{saved},
    updated_at = NOW()
WHERE user_id = #{userId}
  AND post_id = #{postId}

UPDATE posts
SET like_count = GREATEST(like_count + #{delta}, 0)
WHERE id = #{postId}

UPDATE posts
SET save_count = GREATEST(save_count + #{delta}, 0)
WHERE id = #{postId}

UPDATE user_follow_contacts
SET followed = #{followed},
    updated_at = NOW()
WHERE user_id = #{userId}
  AND contact_id = #{contactId}

mapper.select:
SELECT id
FROM alumni_contacts
WHERE contact_code = #{contactCode}

SELECT id
FROM conversations
WHERE owner_user_id = #{userId}
  AND conversation_code = #{conversationCode}

mapper.update:
UPDATE conversations
SET last_message = #{lastMessage},
    display_time = #{displayTime},
    unread_count = 0,
    sort_time = #{sortTime}
WHERE id = #{conversationId}

UPDATE conversations
SET unread_count = 0
WHERE owner_user_id = #{userId}
  AND conversation_code = #{conversationCode}
